const body = $('Webhook').item.json.body || {};
const normalizeArray = (value) => {
  if (Array.isArray(value)) return value.filter(Boolean).map((v) => String(v));
  if (typeof value === 'string' && value.trim()) return value.split(',').map((v) => v.trim()).filter(Boolean);
  return [];
};
return [{ json: { action: String(body.action || 'incidents'), incidentId: String(body.incidentId || ''), nodeId: String(body.nodeId || ''), targetLabels: normalizeArray(body.targetLabels), existingNodeIds: normalizeArray(body.existingNodeIds) } }];

const esc = (s) => String(s || '').replace(/\\/g, '\\\\').replace(/'/g, "\\'");
const quoteList = (values) => `[${values.map((v) => `'${esc(v)}'`).join(',')}]`;
const action = $json.action;
const incidentId = esc($json.incidentId);
const nodeId = esc($json.nodeId);
const targets = quoteList($json.targetLabels || []);
const existing = quoteList($json.existingNodeIds || []);
let query = '';
if (action === 'incidents') {
  query = `MATCH (inc:Incident)
RETURN inc.incident_id AS incident_id,
       elementId(inc) AS element_id,
       coalesce(inc.title, inc.incident_id) AS title,
       inc.timestamp AS timestamp,
       inc.summary AS summary
ORDER BY inc.timestamp DESC
LIMIT 100`;
} else if (action === 'incident_graph') {
  query = `CALL {
  MATCH (inc:Incident {incident_id:'${incidentId}'})
  RETURN [{id: elementId(inc), labels: labels(inc), props: properties(inc)}] AS path_nodes,
         [] AS path_rels
  UNION ALL
  MATCH (inc:Incident {incident_id:'${incidentId}'})
  MATCH p = (inc)-[*1..2]-(n)
  WHERE NOT n:Incident OR elementId(n) = elementId(inc)
  RETURN [node IN nodes(p) | {id: elementId(node), labels: labels(node), props: properties(node)}] AS path_nodes,
         [rel IN relationships(p) | {source: elementId(startNode(rel)), target: elementId(endNode(rel)), type: type(rel), props: properties(rel)}] AS path_rels
}
RETURN path_nodes, path_rels
LIMIT 400`;
} else if (action === 'node_details') {
  query = `MATCH (n)
WHERE elementId(n) = '${nodeId}'
OPTIONAL MATCH (n)--(m)
WITH n, collect(DISTINCT {id: elementId(m), label: coalesce(m.title, m.name, m.org_name, m.technique_id, m.cve_id, m.value, m.ip, m.domain, m.mitigation_id, m.tactic_id), labels: labels(m)})[0..12] AS neighbors
RETURN elementId(n) AS id, labels(n) AS labels, properties(n) AS props, neighbors`;
} else if (action === 'neighbor_counts') {
  query = `WITH ${existing} AS existingIds
MATCH (n)
WHERE elementId(n) = '${nodeId}'
OPTIONAL MATCH (n)--(m)
WHERE elementId(m) <> '${nodeId}'
  AND NOT elementId(m) IN existingIds
WITH head([l IN labels(m) WHERE NOT l IN ['Base', 'UcoObject']]) AS label
WHERE label IS NOT NULL
RETURN label, count(*) AS count
ORDER BY count DESC, label ASC`;
} else if (action === 'expand_node') {
  query = `WITH ${targets} AS targetLabels, ${existing} AS existingIds
MATCH (n)
WHERE elementId(n) = '${nodeId}'
OPTIONAL MATCH (n)-[r]-(m)
WHERE elementId(m) <> '${nodeId}'
  AND (size(targetLabels) = 0 OR any(l IN labels(m) WHERE l IN targetLabels))
  AND NOT elementId(m) IN existingIds
  AND coalesce(m.title, m.name, m.org_name, m.technique_id, m.cve_id, m.value, m.ip, m.domain, m.mitigation_id, m.tactic_id) IS NOT NULL
RETURN elementId(n) AS source_id, elementId(m) AS node_id, labels(m) AS node_labels, properties(m) AS node_props, type(r) AS rel_type, properties(r) AS rel_props
LIMIT 120`;
} else {
  query = `RETURN 'unsupported_action' AS error, '${esc(action)}' AS action`;
}
return [{ json: { ...$json, query } }];

const all = Array.isArray($json.data) ? $json.data : [];
const request = all[0] || {};
const resultItems = all.slice(1);

const flattenRows = (items) => {
  const rows = [];
  for (const item of items) {
    if (!item || typeof item !== 'object') continue;
    if (Array.isArray(item)) {
      rows.push(...item);
      continue;
    }
    if (Array.isArray(item.data)) {
      rows.push(...item.data);
      continue;
    }
    if (Array.isArray(item.results)) {
      rows.push(...item.results);
      continue;
    }
    if (Array.isArray(item.records)) {
      rows.push(...item.records);
      continue;
    }
    if (Array.isArray(item.rows)) {
      rows.push(...item.rows);
      continue;
    }
    rows.push(item);
  }
  return rows;
};

const rows = flattenRows(resultItems);
const pickLabel = (labels = []) => ['Incident', 'ThreatActor', 'Victim', 'Technique', 'Malware', 'Vulnerability', 'Indicator', 'IPAddress', 'Domain', 'Tool', 'Tactic', 'Mitigation'].find((label) => labels.includes(label)) || labels[0] || 'Unknown';
const pickName = (props = {}, fallback = '') => props.title || props.name || props.org_name || props.technique_id || props.cve_id || props.value || props.ip || props.domain || props.mitigation_id || props.tactic_id || fallback;
const relLabel = (rel) => rel?.props?.relationshipType || rel?.type || 'RELATED_TO';
let payload = { action: request.action, ok: true, rowCount: rows.length };
if (request.action === 'incidents') {
  payload.incidents = rows.filter((row) => row.incident_id).map((row) => ({ incidentId: row.incident_id, elementId: row.element_id, title: row.title, timestamp: row.timestamp, summary: row.summary || '' }));
} else if (request.action === 'incident_graph') {
  const nodes = new Map();
  const links = new Map();
  for (const row of rows) {
    for (const node of (row.path_nodes || [])) {
      if (!node?.id) continue;
      nodes.set(node.id, { id: node.id, label: pickLabel(node.labels || []), name: pickName(node.props || {}, node.id), properties: node.props || {} });
    }
    for (const rel of (row.path_rels || [])) {
      if (!rel?.source || !rel?.target) continue;
      const key = [rel.source, rel.target, relLabel(rel)].sort().join('|');
      if (!links.has(key)) links.set(key, { source: rel.source, target: rel.target, label: relLabel(rel) });
    }
  }
  payload.graph = { nodes: [...nodes.values()], links: [...links.values()] };
} else if (request.action === 'node_details') {
  const row = rows[0] || null;
  payload.node = row ? { id: row.id, label: pickLabel(row.labels || []), name: pickName(row.props || {}, row.id), properties: row.props || {}, neighbors: (row.neighbors || []).filter((neighbor) => neighbor?.id) } : null;
} else if (request.action === 'neighbor_counts') {
  payload.neighborCounts = rows.filter((row) => row.label).map((row) => ({ label: row.label, count: Number(row.count || 0) }));
} else if (request.action === 'expand_node') {
  const nodes = new Map();
  const links = [];
  for (const row of rows) {
    if (!row.node_id) continue;
    nodes.set(row.node_id, { id: row.node_id, label: pickLabel(row.node_labels || []), name: pickName(row.node_props || {}, row.node_id), properties: row.node_props || {} });
    links.push({ source: row.source_id, target: row.node_id, label: row.rel_props?.relationshipType || row.rel_type || 'RELATED_TO' });
  }
  payload.expansion = { nodes: [...nodes.values()], links };
} else {
  payload = { action: request.action, ok: false, error: 'Unsupported action', supportedActions: ['incidents', 'incident_graph', 'node_details', 'neighbor_counts', 'expand_node'] };
}
return [{ json: payload }];
